def execute_workflow(task: str):
    steps = agent.plan(task)  # Decomposes into steps

    for step in steps:
        if step.requires_approval:
            approval = request_human_approval(step.summary)
            if not approval:
                agent.rollback()
                return "Workflow rejected"

        result = agent.execute_step(step)
        agent.memory.save(step.id, result)

        if step.is_final:
            return agent.finalize()

workflow_result = execute_workflow("Process customer order #12345")

import uuid
import requests

@tool_registry.tool
def safe_api_call(url: str, method: str, payload: dict = None):
    idempotency_key = str(uuid.uuid4())
    headers = {'Idempotency-Key': idempotency_key}

    try:
        response = requests.request(method, url, json=payload, headers=headers)
        return {'success': response.status_code < 400, 'data': response.json()}
    except Exception as e:
        agent.trigger_rollback(idempotency_key)
        return {'success': False, 'error': str(e)}

# Usage in workflow
result = safe_api_call('https://api.example.com/orders', 'POST', {'order_id': '12345'})

