from vex_sdk import Vex
from beeai.events import EventBus

# Initialize Vex client
vex = Vex(api_key="your-vex-api-key")

# Define workflow-specific verifiers
@policies.workflow
class WorkflowVerifier:
    def verify_action_correctness(self, event):
        if event.tool == 'api_call':
            assert event.params['url'].startswith('https://approved-domain.com')

    def check_permissions(self, event):
        user_permissions = agent.memory.get('user_permissions')
        assert event.user_id in user_permissions

    def verify_idempotency(self, event):
        assert 'Idempotency-Key' in event.headers

# Register Vex listener
bus = EventBus()
bus.register_listener(vex.listener(WorkflowVerifier()))

@vex.guard('tool_safety')
def validate_workflow_tools(event):
    if event.type == 'tool_call':
        # Block dangerous URLs
        dangerous_domains = ['shell-exec', 'eval', 'localhost']
        for domain in dangerous_domains:
            assert domain not in event.params['url']

        # Validate JSON output format
        if event.model == 'granite':
            assert validate_json_schema(event.output, expected_tool_schema)

@vex.guard('rollback_safety')
def ensure_rollback_capability(event):
    if event.requires_rollback:
        checkpoint = agent.memory.get_checkpoint(event.workflow_id)
        assert checkpoint is not None

bus.register_listener([validate_workflow_tools, ensure_rollback_capability])
